     1→/**
     2→ * OpenAI Provider
     3→ * Access to GPT-4o, o1, and other OpenAI models
     4→ * BYOK (Bring Your Own Key) - User provides paid API key
     5→ */
     6→
     7→import OpenAI from 'openai';
     8→import type {
     9→  AIProvider,
    10→  AIProviderMetadata,
    11→  AIModel,
    12→  AIMessageOptions,
    13→  AIResponse,
    14→} from './types';
    15→import { ProviderError, ProviderErrorType } from './types';
    16→
    17→/**
    18→ * OpenAI provider metadata
    19→ */
    20→const METADATA: AIProviderMetadata = {
    21→  id: 'openai',
    22→  name: 'OpenAI',
    23→  displayName: 'OpenAI',
    24→  description: 'Industry-leading models from OpenAI. Requires paid API key (separate from ChatGPT Plus).',
    25→
    26→  requiresApiKey: true,
    27→  apiKeyUrl: 'https://platform.openai.com/api-keys',
    28→  apiKeyLabel: 'OpenAI API Key',
    29→
    30→  hasFreeModels: false, // No permanent free tier
    31→  freeModelIds: [],
    32→
    33→  supportsCORS: false,
    34→  requiresProxy: true, // OpenAI does NOT support CORS
    35→  supportsStreaming: true,
    36→
    37→  websiteUrl: 'https://openai.com',
    38→  docsUrl: 'https://platform.openai.com/docs',
    39→};
    40→
    41→/**
    42→ * OpenAI models (all paid)
    43→ */
    44→const PAID_MODELS: AIModel[] = [
    45→  {
    46→    id: 'gpt-4o',
    47→    name: 'GPT-4o',
    48→    provider: 'openai',
    49→    speedRating: 4,
    50→    qualityRating: 5,
    51→    contextWindow: 128000,
    52→    maxOutputTokens: 16384,
    53→    supportsStreaming: true,
    54→    supportsVision: true,
    55→    supportsFunctionCalling: true,
    56→    isFree: false,
    57→    costPer1MTokens: 2.5,
    58→    requiresApiKey: true,
    59→    useCases: ['chat', 'code', 'reasoning', 'multimodal'],
    60→    description: 'OpenAI\'s flagship multimodal model. Best all-around performance.',
    61→  },
    62→  {
    63→    id: 'gpt-4o-mini',
    64→    name: 'GPT-4o Mini',
    65→    provider: 'openai',
    66→    speedRating: 5,
    67→    qualityRating: 4,
    68→    contextWindow: 128000,
    69→    maxOutputTokens: 16384,
    70→    supportsStreaming: true,
    71→    supportsVision: true,
    72→    supportsFunctionCalling: true,
    73→    isFree: false,
    74→    costPer1MTokens: 0.15,
    75→    requiresApiKey: true,
    76→    useCases: ['chat', 'code', 'quick-tasks'],
    77→    description: 'Fast, affordable GPT-4 model. Great for most tasks.',
    78→  },
    79→  {
    80→    id: 'o1',
    81→    name: 'o1 (Reasoning)',
    82→    provider: 'openai',
    83→    speedRating: 2,
    84→    qualityRating: 5,
    85→    contextWindow: 200000,
    86→    maxOutputTokens: 100000,
    87→    supportsStreaming: false, // o1 doesn't support streaming
    88→    isFree: false,
    89→    costPer1MTokens: 15.0,
    90→    requiresApiKey: true,
    91→    useCases: ['reasoning', 'math', 'science', 'complex-analysis'],
    92→    description: 'OpenAI\'s reasoning model. Best for complex problems requiring deep thought.',
    93→  },
    94→  {
    95→    id: 'o1-mini',
    96→    name: 'o1-mini (Fast Reasoning)',
    97→    provider: 'openai',
    98→    speedRating: 3,
    99→    qualityRating: 4,
   100→    contextWindow: 128000,
   101→    maxOutputTokens: 65536,
   102→    supportsStreaming: false,
   103→    isFree: false,
   104→    costPer1MTokens: 3.0,
   105→    requiresApiKey: true,
   106→    useCases: ['reasoning', 'code', 'math'],
   107→    description: 'Faster, cheaper reasoning model for coding and STEM tasks.',
   108→  },
   109→];
   110→
   111→/**
   112→ * OpenAI AI Provider Implementation
   113→ */
   114→export class OpenAIProvider implements AIProvider {
   115→  metadata = METADATA;
   116→  models = PAID_MODELS;
   117→
   118→  private client: OpenAI | null = null;
   119→  private apiKey: string | null = null;
   120→
   121→  /**
   122→   * Check if provider is configured with API key
   123→   */
   124→  isConfigured(): boolean {
   125→    return !!this.apiKey && !!this.client;
   126→  }
   127→
   128→  /**
   129→   * Set API key and initialize client
   130→   */
   131→  setApiKey(apiKey: string): void {
   132→    this.apiKey = apiKey;
   133→    this.client = new OpenAI({
   134→      apiKey: apiKey,
   135→      dangerouslyAllowBrowser: true, // Note: OpenAI doesn't support CORS, this will likely fail
   136→    });
   137→  }
   138→
   139→  /**
   140→   * Get current API key
   141→   */
   142→  getApiKey(): string | null {
   143→    return this.apiKey;
   144→  }
   145→
   146→  /**
   147→   * Clear API key and client
   148→   */
   149→  clearApiKey(): void {
   150→    this.apiKey = null;
   151→    this.client = null;
   152→  }
   153→
   154→  /**
   155→   * Validate API key by making a test request
   156→   */
   157→  async validateApiKey(apiKey: string): Promise<boolean> {
   158→    try {
   159→      const testClient = new OpenAI({
   160→        apiKey: apiKey,
   161→        dangerouslyAllowBrowser: true,
   162→      });
   163→
   164→      // Try to list models (minimal API call)
   165→      await testClient.models.list();
   166→      return true;
   167→    } catch (error: any) {
   168→      console.error('OpenAI API key validation failed:', error);
   169→      return false;
   170→    }
   171→  }
   172→
   173→  /**
   174→   * Get model by ID
   175→   */
   176→  getModel(modelId: string): AIModel | null {
   177→    return this.models.find((m) => m.id === modelId) || null;
   178→  }
   179→
   180→  /**
   181→   * Get default model
   182→   */
   183→  getDefaultModel(): AIModel {
   184→    return PAID_MODELS[1]; // GPT-4o Mini (most affordable)
   185→  }
   186→
   187→  /**
   188→   * Get all free models
   189→   */
   190→  getFreeModels(): AIModel[] {
   191→    return []; // No free models
   192→  }
   193→
   194→  /**
   195→   * Send message to OpenAI
   196→   */
   197→  async sendMessage(model: string, options: AIMessageOptions): Promise<AIResponse> {
   198→    if (!this.client) {
   199→      throw new ProviderError(
   200→        ProviderErrorType.INVALID_API_KEY,
   201→        'OpenAI provider not configured. Please add your OpenAI API key.',
   202→        'openai'
   203→      );
   204→    }
   205→
   206→    try {
   207→      const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [];
   208→
   209→      // Add system prompt if provided
   210→      if (options.systemPrompt) {
   211→        messages.push({
   212→          role: 'system',
   213→          content: options.systemPrompt,
   214→        });
   215→      }
   216→
   217→      // Add conversation history
   218→      if (options.conversationHistory) {
   219→        options.conversationHistory.forEach((msg) => {
   220→          messages.push({
   221→            role: msg.role === 'assistant' ? 'assistant' : 'user',
   222→            content: msg.content,
   223→          });
   224→        });
   225→      }
   226→
   227→      // Add current user prompt
   228→      messages.push({
   229→        role: 'user',
   230→        content: options.prompt,
   231→      });
   232→
   233→      // Check if model supports streaming (o1 models don't)
   234→      const modelInfo = this.getModel(model);
   235→      const canStream = modelInfo?.supportsStreaming !== false;
   236→
   237→      // Send request
   238→      if (options.stream && options.onChunk && canStream) {
   239→        // Streaming mode
   240→        const stream = await this.client.chat.completions.create({
   241→          model: model,
   242→          messages: messages,
   243→          temperature: options.temperature || 0.7,
   244→          max_tokens: options.maxTokens || 2048,
   245→          stream: true,
   246→        });
   247→
   248→        let fullContent = '';
   249→        for await (const chunk of stream) {
   250→          const content = chunk.choices[0]?.delta?.content || '';
   251→          fullContent += content;
   252→          if (content && options.onChunk) {
   253→            options.onChunk(content);
   254→          }
   255→        }
   256→
   257→        return {
   258→          content: fullContent,
   259→          model: model,
   260→          provider: 'openai',
   261→          finishReason: 'stop',
   262→        };
   263→      } else {
   264→        // Non-streaming mode (or model doesn't support streaming)
   265→        const completion = await this.client.chat.completions.create({
   266→          model: model,
   267→          messages: messages,
   268→          temperature: options.temperature || 0.7,
   269→          max_tokens: options.maxTokens || 2048,
   270→          stream: false,
   271→        });
   272→
   273→        const content = completion.choices[0]?.message?.content || '';
   274→
   275→        return {
   276→          content: content,
   277→          model: model,
   278→          provider: 'openai',
   279→          finishReason: completion.choices[0]?.finish_reason as 'stop' | 'length' | undefined,
   280→          usage: completion.usage ? {
   281→            promptTokens: completion.usage.prompt_tokens,
   282→            completionTokens: completion.usage.completion_tokens,
   283→            totalTokens: completion.usage.total_tokens,
   284→          } : undefined,
   285→        };
   286→      }
   287→    } catch (error: any) {
   288→      // Map OpenAI errors to ProviderError
   289→      if (error?.status === 401 || error?.message?.includes('Incorrect API key')) {
   290→        throw new ProviderError(
   291→          ProviderErrorType.INVALID_API_KEY,
   292→          'Invalid OpenAI API key. Please check your API key and try again.',
   293→          'openai'
   294→        );
   295→      } else if (error?.status === 429 || error?.message?.includes('rate limit')) {
   296→        throw new ProviderError(
   297→          ProviderErrorType.RATE_LIMIT,
   298→          'OpenAI rate limit exceeded. Please wait a moment and try again.',
   299→          'openai',
   300→          true // retryable
   301→        );
   302→      } else if (error?.status === 402 || error?.message?.includes('quota') || error?.message?.includes('billing')) {
   303→        throw new ProviderError(
   304→          ProviderErrorType.QUOTA_EXCEEDED,
   305→          'OpenAI quota exceeded or billing issue. Please check your account.',
   306→          'openai'
   307→        );
   308→      } else if (error?.status === 404 || error?.message?.includes('model')) {
   309→        throw new ProviderError(
   310→          ProviderErrorType.MODEL_NOT_FOUND,
   311→          `Model "${model}" not found on OpenAI.`,
