/**
 * OpenAI Provider
 * Access to GPT-4o, o1, and other OpenAI models
 * BYOK (Bring Your Own Key) - User provides paid API key
 */

import OpenAI from 'openai';
import type {
  AIProvider,
  AIProviderMetadata,
  AIModel,
  AIMessageOptions,
  AIResponse,
} from './types';
import { ProviderError, ProviderErrorType } from './types';

/**
 * OpenAI provider metadata
 */
const METADATA: AIProviderMetadata = {
  id: 'openai',
  name: 'OpenAI',
  displayName: 'OpenAI',
  description: 'Industry-leading models from OpenAI. Requires paid API key (separate from ChatGPT Plus).',

  requiresApiKey: true,
  apiKeyUrl: 'https://platform.openai.com/api-keys',
  apiKeyLabel: 'OpenAI API Key',

  hasFreeModels: false, // No permanent free tier
  freeModelIds: [],

  supportsCORS: false,
  requiresProxy: true, // OpenAI does NOT support CORS
  supportsStreaming: true,

  websiteUrl: 'https://openai.com',
  docsUrl: 'https://platform.openai.com/docs',
};

/**
 * OpenAI models (all paid)
 */
const PAID_MODELS: AIModel[] = [
  {
    id: 'gpt-4o',
    name: 'GPT-4o',
    provider: 'openai',
    speedRating: 4,
    qualityRating: 5,
    contextWindow: 128000,
    maxOutputTokens: 16384,
    supportsStreaming: true,
    supportsVision: true,
    supportsFunctionCalling: true,
    isFree: false,
    costPer1MTokens: 2.5,
    requiresApiKey: true,
    useCases: ['chat', 'code', 'reasoning', 'multimodal'],
    description: 'OpenAI\'s flagship multimodal model. Best all-around performance.',
  },
  {
    id: 'gpt-4o-mini',
    name: 'GPT-4o Mini',
    provider: 'openai',
    speedRating: 5,
    qualityRating: 4,
    contextWindow: 128000,
    maxOutputTokens: 16384,
    supportsStreaming: true,
    supportsVision: true,
    supportsFunctionCalling: true,
    isFree: false,
    costPer1MTokens: 0.15,
    requiresApiKey: true,
    useCases: ['chat', 'code', 'quick-tasks'],
    description: 'Fast, affordable GPT-4 model. Great for most tasks.',
  },
  {
    id: 'o1',
    name: 'o1 (Reasoning)',
    provider: 'openai',
    speedRating: 2,
    qualityRating: 5,
    contextWindow: 200000,
    maxOutputTokens: 100000,
    supportsStreaming: false, // o1 doesn't support streaming
    isFree: false,
    costPer1MTokens: 15.0,
    requiresApiKey: true,
    useCases: ['reasoning', 'math', 'science', 'complex-analysis'],
    description: 'OpenAI\'s reasoning model. Best for complex problems requiring deep thought.',
  },
  {
    id: 'o1-mini',
    name: 'o1-mini (Fast Reasoning)',
    provider: 'openai',
    speedRating: 3,
    qualityRating: 4,
    contextWindow: 128000,
    maxOutputTokens: 65536,
    supportsStreaming: false,
    isFree: false,
    costPer1MTokens: 3.0,
    requiresApiKey: true,
    useCases: ['reasoning', 'code', 'math'],
    description: 'Faster, cheaper reasoning model for coding and STEM tasks.',
  },
];

/**
 * OpenAI AI Provider Implementation
 */
export class OpenAIProvider implements AIProvider {
  metadata = METADATA;
  models = PAID_MODELS;

  private client: OpenAI | null = null;
  private apiKey: string | null = null;

  /**
   * Check if provider is configured with API key
   */
  isConfigured(): boolean {
    return !!this.apiKey && !!this.client;
  }

  /**
   * Set API key and initialize client
   */
  setApiKey(apiKey: string): void {
    this.apiKey = apiKey;
    this.client = new OpenAI({
      apiKey: apiKey,
      dangerouslyAllowBrowser: true, // Note: OpenAI doesn't support CORS, this will likely fail
    });
  }

  /**
   * Get current API key
   */
  getApiKey(): string | null {
    return this.apiKey;
  }

  /**
   * Clear API key and client
   */
  clearApiKey(): void {
    this.apiKey = null;
    this.client = null;
  }

  /**
   * Validate API key by making a test request
   */
  async validateApiKey(apiKey: string): Promise<boolean> {
    try {
      const testClient = new OpenAI({
        apiKey: apiKey,
        dangerouslyAllowBrowser: true,
      });

      // Try to list models (minimal API call)
      await testClient.models.list();
      return true;
    } catch (error: any) {
      console.error('OpenAI API key validation failed:', error);
      return false;
    }
  }

  /**
   * Get model by ID
   */
  getModel(modelId: string): AIModel | null {
    return this.models.find((m) => m.id === modelId) || null;
  }

  /**
   * Get default model
   */
  getDefaultModel(): AIModel {
    return PAID_MODELS[1]; // GPT-4o Mini (most affordable)
  }

  /**
   * Get all free models
   */
  getFreeModels(): AIModel[] {
    return []; // No free models
  }

  /**
   * Send message to OpenAI
   */
  async sendMessage(model: string, options: AIMessageOptions): Promise<AIResponse> {
    if (!this.client) {
      throw new ProviderError(
        ProviderErrorType.INVALID_API_KEY,
        'OpenAI provider not configured. Please add your OpenAI API key.',
        'openai'
      );
    }

    try {
      const messages: OpenAI.Chat.ChatCompletionMessageParam[] = [];

      // Add system prompt if provided
      if (options.systemPrompt) {
        messages.push({
          role: 'system',
          content: options.systemPrompt,
        });
      }

      // Add conversation history
      if (options.conversationHistory) {
        options.conversationHistory.forEach((msg) => {
          messages.push({
            role: msg.role === 'assistant' ? 'assistant' : 'user',
            content: msg.content,
          });
        });
      }

      // Add current user prompt
      messages.push({
        role: 'user',
        content: options.prompt,
      });

      // Check if model supports streaming (o1 models don't)
      const modelInfo = this.getModel(model);
      const canStream = modelInfo?.supportsStreaming !== false;

      // Send request
      if (options.stream && options.onChunk && canStream) {
        // Streaming mode
        const stream = await this.client.chat.completions.create({
          model: model,
          messages: messages,
          temperature: options.temperature || 0.7,
          max_tokens: options.maxTokens || 2048,
          stream: true,
        });

        let fullContent = '';
        for await (const chunk of stream) {
          const content = chunk.choices[0]?.delta?.content || '';
          fullContent += content;
          if (content && options.onChunk) {
            options.onChunk(content);
          }
        }

        return {
          content: fullContent,
          model: model,
          provider: 'openai',
          finishReason: 'stop',
        };
      } else {
        // Non-streaming mode (or model doesn't support streaming)
        const completion = await this.client.chat.completions.create({
          model: model,
          messages: messages,
          temperature: options.temperature || 0.7,
          max_tokens: options.maxTokens || 2048,
          stream: false,
        });

        const content = completion.choices[0]?.message?.content || '';

        return {
          content: content,
          model: model,
          provider: 'openai',
          finishReason: completion.choices[0]?.finish_reason as 'stop' | 'length' | undefined,
          usage: completion.usage ? {
            promptTokens: completion.usage.prompt_tokens,
            completionTokens: completion.usage.completion_tokens,
            totalTokens: completion.usage.total_tokens,
          } : undefined,
        };
      }
    } catch (error: any) {
      // Map OpenAI errors to ProviderError
      if (error?.status === 401 || error?.message?.includes('Incorrect API key')) {
        throw new ProviderError(
          ProviderErrorType.INVALID_API_KEY,
          'Invalid OpenAI API key. Please check your API key and try again.',
          'openai'
        );
      } else if (error?.status === 429 || error?.message?.includes('rate limit')) {
        throw new ProviderError(
          ProviderErrorType.RATE_LIMIT,
          'OpenAI rate limit exceeded. Please wait a moment and try again.',
          'openai',
          true // retryable
        );
      } else if (error?.status === 402 || error?.message?.includes('quota') || error?.message?.includes('billing')) {
        throw new ProviderError(
          ProviderErrorType.QUOTA_EXCEEDED,
          'OpenAI quota exceeded or billing issue. Please check your account.',
          'openai'
        );
      } else if (error?.status === 404 || error?.message?.includes('model')) {
        throw new ProviderError(
          ProviderErrorType.MODEL_NOT_FOUND,
          `Model "${model}" not found on OpenAI.`,
          'openai'
        );
      } else if (error?.message?.includes('CORS') || error?.message?.includes('fetch')) {
        throw new ProviderError(
          ProviderErrorType.NETWORK_ERROR,
          'OpenAI requires backend proxy for browser use. CORS error encountered.',
          'openai'
        );
      } else {
        throw new ProviderError(
          ProviderErrorType.UNKNOWN,
          `OpenAI error: ${error?.message || 'Unknown error occurred'}`,
          'openai'
        );
      }
    }
  }
}

// Singleton instance
export const openaiProvider = new OpenAIProvider();

/**
 * AI Provider Types and Interfaces
 * Defines the contract for all AI provider implementations
 */

/**
 * AI Model metadata
 */
export interface AIModel {
  id: string; // Unique model identifier (e.g., "gpt-4o", "llama-3.3-70b")
  name: string; // Display name (e.g., "GPT-4o", "Llama 3.3 70B")
  provider: string; // Provider ID (e.g., "openai", "groq")

  // Performance characteristics
  speedRating: 1 | 2 | 3 | 4 | 5; // 1 = slow, 5 = lightning fast
  qualityRating: 1 | 2 | 3 | 4 | 5; // 1 = basic, 5 = excellent

  // Capabilities
  contextWindow: number; // Max tokens in context (e.g., 128000)
  maxOutputTokens?: number; // Max tokens in response
  supportsStreaming: boolean; // Can stream responses
  supportsVision?: boolean; // Can process images
  supportsFunctionCalling?: boolean; // Can call functions

  // Cost and availability
  isFree: boolean; // Available on free tier
  costPer1MTokens?: number; // Cost in USD per 1M tokens (if paid)
  requiresApiKey: boolean; // Needs API key

  // Use cases
  useCases: string[]; // ["chat", "code", "reasoning", "creative"]
  description?: string; // Brief description of model strengths
}

/**
 * AI Provider metadata
 */
export interface AIProviderMetadata {
  id: string; // Unique provider ID (e.g., "openai", "groq")
  name: string; // Display name (e.g., "OpenAI", "Groq")
  displayName: string; // Branded name for UI
  description: string; // Brief description

  // Authentication
  requiresApiKey: boolean; // Needs API key
  apiKeyUrl?: string; // Where to get API key
  apiKeyLabel?: string; // Label for API key input (e.g., "OpenAI API Key")

  // Availability
  hasFreeModels: boolean; // Has free tier models
  freeModelIds?: string[]; // IDs of free models

  // Rate limits (free tier)
  freeTierLimits?: {
    requestsPerMinute?: number;
    requestsPerDay?: number;
    tokensPerMinute?: number;
    tokensPerDay?: number;
    description?: string; // Human-readable description
  };

  // Features
  supportsCORS?: boolean; // Can be called from browser
  requiresProxy?: boolean; // Needs backend proxy
  supportsStreaming: boolean; // Can stream responses

  // Branding
  logoUrl?: string; // Provider logo
  websiteUrl?: string; // Provider website
  docsUrl?: string; // API documentation
}

/**
 * AI message options
 */
export interface AIMessageOptions {
  prompt: string; // User message
  conversationHistory?: Array<{ role: 'user' | 'assistant' | 'system'; content: string }>; // Previous messages
  systemPrompt?: string; // System instruction
  temperature?: number; // 0-1, creativity level
  maxTokens?: number; // Max response length
  stream?: boolean; // Enable streaming
  onChunk?: (chunk: string) => void; // Stream callback
}

/**
 * AI response
 */
export interface AIResponse {
  content: string; // Response text
  model: string; // Model used
  provider: string; // Provider used
  finishReason?: 'stop' | 'length' | 'error'; // Why generation stopped
  usage?: {
    promptTokens: number;
    completionTokens: number;
    totalTokens: number;
  };
}

/**
 * Provider error types
 */
export const ProviderErrorType = {
  INVALID_API_KEY: 'invalid_api_key',
  RATE_LIMIT: 'rate_limit',
  QUOTA_EXCEEDED: 'quota_exceeded',
  MODEL_NOT_FOUND: 'model_not_found',
  NETWORK_ERROR: 'network_error',
  TIMEOUT: 'timeout',
  UNKNOWN: 'unknown',
} as const;

export type ProviderErrorType = typeof ProviderErrorType[keyof typeof ProviderErrorType];

/**
 * Provider error
 */
export class ProviderError extends Error {
  type: ProviderErrorType;
  provider: string;
  retryable: boolean;

  constructor(
    type: ProviderErrorType,
    message: string,
    provider: string,
    retryable: boolean = false
  ) {
    super(message);
    this.name = 'ProviderError';
    this.type = type;
    this.provider = provider;
    this.retryable = retryable;
  }
}

/**
 * AI Provider interface
 * All provider implementations must implement this interface
 */
export interface AIProvider {
  // Metadata
  metadata: AIProviderMetadata;
  models: AIModel[];

  // Configuration
  isConfigured(): boolean; // Has valid API key
  setApiKey(apiKey: string): void;
  getApiKey(): string | null;
  clearApiKey(): void;

  // Validation
  validateApiKey(apiKey: string): Promise<boolean>;

  // Model operations
  getModel(modelId: string): AIModel | null;
  getDefaultModel(): AIModel;
  getFreeModels(): AIModel[];

  // Messaging
  sendMessage(model: string, options: AIMessageOptions): Promise<AIResponse>;

  // Usage tracking
  getUsage?(): Promise<{ requestsToday: number; tokensToday: number; limitReached: boolean }>;
}

/**
 * Provider selection criteria
 */
export interface ProviderSelectionCriteria {
  requireFree?: boolean; // Only free models
  requireFast?: boolean; // Prioritize speed
  requireHighQuality?: boolean; // Prioritize quality
  minContextWindow?: number; // Minimum context size
  useCase?: string; // Specific use case
}

/**
 * Provider router configuration
 */
export interface ProviderRouterConfig {
  primaryProvider: string; // Primary provider ID
  primaryModel: string; // Primary model ID
  fallbackEnabled: boolean; // Enable automatic fallbacks
  fallbackOrder: string[]; // Provider IDs in fallback order
  notifyOnFallback: boolean; // Show notification when falling back
}

/**
 * Usage statistics
 */
export interface ProviderUsageStats {
  provider: string;
  model: string;
  requestsToday: number;
  tokensToday: number;
  lastRequestAt: Date | null;
  limitReached: boolean;
  resetAt?: Date; // When limits reset
}

