   288→                      </button>
   289→
   290→                      <button
   291→                        onClick={() => handleTestApiKey(providerId)}
   292→                        disabled={!apiKeyInputs[providerId]?.trim() || validating[providerId]}
   293→                        className="px-2.5 py-1 bg-surface-light-elevated dark:bg-surface-dark-elevated hover:bg-surface-light dark:hover:bg-neutral-800 disabled:opacity-50 disabled:cursor-not-allowed border border-border-light dark:border-border-dark rounded-button text-xs text-text-light-primary dark:text-text-dark-primary transition-all duration-standard ease-smooth"
   294→                      >
   295→                        {validating[providerId] ? 'Testing...' : 'Test Key'}
   296→                      </button>
   297→
   298→                      {isConfigured && (
   299→                        <button
   300→                          onClick={() => handleClearApiKey(providerId)}
   301→                          className="px-2.5 py-1 bg-red-500/10 hover:bg-red-500/20 border border-red-500/20 rounded-button text-xs text-red-500 transition-all duration-standard ease-smooth"
   302→                        >
   303→                          Remove
   304→                        </button>
   305→                      )}
   306→
   307→                      {/* Validation Result */}
   308→                      {validationResults[providerId] !== null && (
   309→                        <span
   310→                          className={`px-1.5 py-1 text-[10px] rounded-button ${
   311→                            validationResults[providerId]
   312→                              ? 'bg-green-500/10 text-green-500'
   313→                              : 'bg-red-500/10 text-red-500'
   314→                          }`}
   315→                        >
   316→                          {validationResults[providerId] ? '✓ Valid' : '✗ Invalid'}
   317→                        </span>
   318→                      )}
   319→                    </div>
   320→                  </div>
   321→                </div>
   322→              );
   323→            })}
   324→          </div>
   325→
   326→          {/* Footer Actions */}
   327→          <div className="flex justify-end pt-3 border-t border-border-light dark:border-border-dark">
   328→            <button
   329→              onClick={onClose}
   330→              className="px-3 py-1.5 bg-accent-blue hover:bg-accent-blue-hover text-white rounded-button text-xs transition-all duration-standard ease-smooth"
   331→            >
   332→              Done
   333→            </button>
   334→          </div>
   335→        </div>
   336→      </Modal>
   337→
   338→      {/* Password Prompt Modal */}
   339→      <PasswordPrompt
   340→        isOpen={showPasswordPrompt}
   341→        onSubmit={handlePasswordSubmit}
   342→        onCancel={() => {
   343→          setShowPasswordPrompt(false);
   344→          setSelectedProvider(null);
   345→        }}
   346→        mode={passwordHash ? 'unlock' : 'setup'}
   347→        existingPasswordHash={passwordHash || undefined}
   348→      />
   349→    </>
   350→  );
   351→}
